import re

def parse_duration(s: str) -> int:
    """
    Parses a duration string like '2h30m' and returns total seconds.
    Raises ValueError on invalid input.
    """
    if not re.fullmatch(r'^((\d+)(h|m|s))+$', s):
        raise ValueError(f"Invalid duration: {s!r}")
    parts = re.findall(r'(\d+)(h|m|s)', s)
    total = 0
    for num_str, unit in parts:
        num = int(num_str)
        if unit == 'h':
            total += num * 3600
        elif unit == 'm':
            total += num * 60
        elif unit == 's':
            total += num
    return total
